import type { MouseEvent } from "react";
import type { TodoItem } from "../../todo-rich-card/types";
import { useTodoTreeRenderContext } from "../hooks/use-todo-tree-context";
import { TodoTreeChevron } from "./todo-tree-chevron";
import { TodoTreeStatusIndicator } from "./todo-tree-status-indicator";
import { TodoTreeCheckbox } from "./todo-tree-checkbox";
import { TodoTreeName } from "./todo-tree-name";
import { TodoTreeDescription } from "./todo-tree-description";
import { TodoTreePersonLabel } from "./todo-tree-person-label";
import { cn } from "@/lib/utils";

export interface TodoTreeRowContentProps {
  item: TodoItem;
  level: number;
  isSelected: boolean;
  isCollapsed: boolean;
  /**
   * Visual dimming flag from the filter-fade path. The container also fades;
   * the inner controls stay full opacity so checkbox / chevron remain
   * affordant. Set by the host based on visibleItems[i].dimmed.
   */
  dimmed?: boolean;
  /** Read-only when both the row-level + item-level toggle gates deny. */
  canToggleActive?: boolean;
  onToggleCollapse?: (event: MouseEvent<HTMLButtonElement>) => void;
  onToggleActive?: (nextActive: boolean) => void;
  className?: string;
}

/**
 * Default `renderRow` paint. Composes the leaf primitives with the consumer's
 * slot overrides (name / description / person / statusIndicator) pulled from
 * the render context. Interactive callbacks pass through from `<TodoTreeRow>`
 * (lands in C6) — keeping the content itself props-only makes it testable
 * without a full DnD host.
 */
export function TodoTreeRowContent({
  item,
  level,
  isSelected,
  isCollapsed,
  dimmed,
  canToggleActive = true,
  onToggleCollapse,
  onToggleActive,
  className,
}: TodoTreeRowContentProps) {
  const {
    statusIndicator,
    statusOptionMap,
    indentSize,
    renderName,
    renderDescription,
    renderPerson,
    renderStatusIndicator,
  } = useTodoTreeRenderContext();

  const statusOption = statusOptionMap.get(item.status);
  const hasChildren = !!item.children && item.children.length > 0;
  const fieldArgs = { item, level } as const;
  const stripIndicator = statusIndicator === "strip";

  return (
    <div
      data-level={level}
      data-selected={isSelected || undefined}
      data-collapsed={isCollapsed || undefined}
      data-dimmed={dimmed || undefined}
      data-active={item.active}
      className={cn(
        "relative flex flex-col justify-center gap-0.5 py-1.5 pr-2",
        dimmed && "opacity-50",
        className,
      )}
      style={{
        // Indent + 8px gutter for chevron alignment.
        paddingInlineStart:
          (stripIndicator ? 12 : 8) + level * indentSize,
      }}
    >
      {stripIndicator && (
        <TodoTreeStatusIndicator variant="strip" statusOption={statusOption} />
      )}

      <div className="flex min-w-0 items-center gap-1.5">
        <TodoTreeChevron
          collapsed={isCollapsed}
          hasChildren={hasChildren}
          onToggle={onToggleCollapse}
        />

        {renderStatusIndicator
          ? renderStatusIndicator({ ...fieldArgs, statusOption })
          : statusIndicator === "dot" && (
              <TodoTreeStatusIndicator
                variant="dot"
                statusOption={statusOption}
              />
            )}

        <TodoTreeCheckbox
          checked={item.active}
          disabled={!canToggleActive}
          onChange={onToggleActive}
          ariaLabel={item.active ? `Mark ${item.name} inactive` : `Mark ${item.name} active`}
        />

        {renderName ? (
          <span className="min-w-0 flex-1 truncate">
            {renderName(fieldArgs)}
          </span>
        ) : (
          <TodoTreeName name={item.name} active={item.active} />
        )}

        {item.targetPerson &&
          (renderPerson ? (
            <span className="shrink-0">{renderPerson(fieldArgs)}</span>
          ) : (
            <TodoTreePersonLabel person={item.targetPerson} />
          ))}
      </div>

      {item.description &&
        (renderDescription ? (
          <div
            className="min-w-0"
            style={{
              paddingInlineStart: 16,
            }}
          >
            {renderDescription(fieldArgs)}
          </div>
        ) : (
          <div
            className="min-w-0"
            style={{
              paddingInlineStart: 16,
            }}
          >
            <TodoTreeDescription description={item.description} />
          </div>
        ))}
    </div>
  );
}

"use client";

import { useEffect, useRef } from "react";
import type { TodoPermissions } from "../../todo-rich-card/types";
import type { TodoTreePermissionDeniedEvent } from "../types";
import {
  useTodoTreeRenderContext,
  useTodoTreeStateContext,
} from "../hooks/use-todo-tree-context";
import {
  useTreeVirtual,
  type TodoTreeVirtualizeMode,
} from "../hooks/use-tree-virtual";
import { useTreeKeyboard } from "../hooks/use-tree-keyboard";
import { TodoTreeRow } from "./todo-tree-row";
import { TodoTreeEmptyState } from "./todo-tree-empty-state";
import { isFilterActive } from "../lib/filter-items";
import { evalPermission } from "../lib/permissions";
import { cn } from "@/lib/utils";

export interface TodoTreeListProps {
  /** Default "auto" — virtualize when total rows ≥ threshold (R9 lock). */
  virtualize?: TodoTreeVirtualizeMode;
  /** Default 200 (plan §10.2). */
  virtualizeThreshold?: number;
  /** Default 52 (Q-P2 fixed row height). */
  rowHeight?: number;
  /**
   * When true, virtualization auto-suspends (R7 mitigation). Wired by C6's
   * DnD hooks so virtualizer + drag don't fight over scroll position.
   */
  suspended?: boolean;
  /** Forwarded into the keyboard hook so Space + Delete honor permissions. */
  permissions?: TodoPermissions;
  /** Forwarded into the keyboard hook for permission-denied events. */
  onPermissionDenied?: (args: TodoTreePermissionDeniedEvent) => void;
  /** When true, keyboard Space + Delete fire `denied-by-readOnly`. */
  readOnly?: boolean;
  className?: string;
}

/**
 * List view over `visibleItems`. Optionally virtualizes via
 * `@tanstack/react-virtual` when the total tree exceeds the threshold OR
 * when the consumer forces "always". Static list paint otherwise so DnD
 * indicators + slot rows with variable heights work without virtualizer
 * measurement overrides.
 *
 * Owns the tree's keydown handler + focus management + empty-state slot.
 * One row at a time has tabIndex=0 (the focused row or the first visible
 * when nothing is focused); a useEffect programmatically focuses the
 * matching DOM element when state.focusedItemId changes.
 */
export function TodoTreeList({
  virtualize = "auto",
  virtualizeThreshold = 200,
  rowHeight = 52,
  suspended = false,
  permissions,
  onPermissionDenied,
  readOnly,
  className,
}: TodoTreeListProps) {
  const state = useTodoTreeStateContext();
  const { renderEmptyState } = useTodoTreeRenderContext();
  const scrollRef = useRef<HTMLDivElement | null>(null);
  const { onKeyDown } = useTreeKeyboard({
    state,
    permissions,
    onPermissionDenied,
    readOnly,
  });

  const { active, virtualizer } = useTreeVirtual({
    rows: state.visibleItems,
    scrollRef,
    mode: virtualize,
    threshold: virtualizeThreshold,
    rowHeight,
    suspended,
  });

  const rows = state.visibleItems;

  // Resolve the tabbable row id: the focused one if it's still visible, else
  // the first visible row. Lets Tab into the tree always land on something
  // meaningful and keeps the WAI-ARIA "exactly one tabindex=0 treeitem" rule.
  const tabbableId =
    state.focusedItemId &&
    rows.some((r) => r.item.id === state.focusedItemId)
      ? state.focusedItemId
      : (rows[0]?.item.id ?? null);

  // Sync DOM focus to focusedItemId. Only fires when the id changes — clicks
  // that don't change focus don't re-trigger focus() (which would clobber a
  // text input the consumer might've focused from a slot row).
  useEffect(() => {
    if (!state.focusedItemId || !scrollRef.current) return;
    const el = scrollRef.current.querySelector<HTMLElement>(
      `[data-treeitem-id="${CSS.escape(state.focusedItemId)}"]`,
    );
    if (el && document.activeElement !== el) {
      el.focus({ preventScroll: false });
    }
  }, [state.focusedItemId]);

  const hasFilter = isFilterActive(state.filter, state.query);

  if (rows.length === 0) {
    const emptyArgs = { hasFilter };
    const emptyContent = renderEmptyState
      ? renderEmptyState(emptyArgs)
      : <TodoTreeEmptyState hasFilter={hasFilter} />;
    return (
      <div
        ref={scrollRef}
        className={cn("h-full overflow-auto", className)}
        role="tree"
        aria-label="Todo tree"
        aria-multiselectable="true"
        onKeyDown={onKeyDown}
      >
        {emptyContent}
      </div>
    );
  }

  if (active) {
    const virtualItems = virtualizer.getVirtualItems();
    return (
      <div
        ref={scrollRef}
        className={cn("h-full overflow-auto", className)}
        role="tree"
        aria-label="Todo tree"
        aria-multiselectable="true"
        onKeyDown={onKeyDown}
      >
        <div
          style={{
            height: virtualizer.getTotalSize(),
            position: "relative",
            width: "100%",
          }}
        >
          {virtualItems.map((vRow) => {
            const row = rows[vRow.index];
            return (
              <div
                key={row.item.id}
                data-treeitem-id={row.item.id}
                style={{
                  position: "absolute",
                  top: 0,
                  left: 0,
                  width: "100%",
                  transform: `translateY(${vRow.start}px)`,
                  height: vRow.size,
                }}
                role="treeitem"
                tabIndex={tabbableId === row.item.id ? 0 : -1}
                aria-level={row.level + 1}
                aria-expanded={
                  row.item.children && row.item.children.length > 0
                    ? !state.collapsedIds.has(row.item.id)
                    : undefined
                }
                aria-selected={state.selectedIds.has(row.item.id) || undefined}
                onFocus={() => {
                  if (state.focusedItemId !== row.item.id) {
                    state.focusItem(row.item.id);
                  }
                }}
              >
                <TodoTreeRow
                  item={row.item}
                  level={row.level}
                  isSelected={state.selectedIds.has(row.item.id)}
                  isCollapsed={state.collapsedIds.has(row.item.id)}
                  dimmed={row.dimmed}
                  canDrag={!readOnly && evalPermission(permissions, "drag", row.item, row.level)}
                  canToggleActive={
                    !readOnly &&
                    evalPermission(permissions, "toggleActive", row.item, row.level)
                  }
                />
              </div>
            );
          })}
        </div>
      </div>
    );
  }

  // Static list paint (small trees + dragging).
  return (
    <div
      ref={scrollRef}
      className={cn("h-full overflow-auto", className)}
      role="tree"
      aria-label="Todo tree"
      aria-multiselectable="true"
      onKeyDown={onKeyDown}
    >
      <div className="flex flex-col">
        {rows.map((row) => (
          <div
            key={row.item.id}
            data-treeitem-id={row.item.id}
            role="treeitem"
            tabIndex={tabbableId === row.item.id ? 0 : -1}
            aria-level={row.level + 1}
            aria-expanded={
              row.item.children && row.item.children.length > 0
                ? !state.collapsedIds.has(row.item.id)
                : undefined
            }
            aria-selected={state.selectedIds.has(row.item.id) || undefined}
            onFocus={() => {
              if (state.focusedItemId !== row.item.id) {
                state.focusItem(row.item.id);
              }
            }}
          >
            <TodoTreeRow
              item={row.item}
              level={row.level}
              isSelected={state.selectedIds.has(row.item.id)}
              isCollapsed={state.collapsedIds.has(row.item.id)}
              dimmed={row.dimmed}
              canDrag={!readOnly && evalPermission(permissions, "drag", row.item, row.level)}
              canToggleActive={
                !readOnly &&
                evalPermission(permissions, "toggleActive", row.item, row.level)
              }
            />
          </div>
        ))}
      </div>
    </div>
  );
}

"use client";

import { useDroppable } from "@dnd-kit/core";
import type { MouseEvent } from "react";
import type { TodoItem } from "../../todo-rich-card/types";
import { TodoTreeRowContent } from "./todo-tree-row-content";
import { TodoTreeGrip } from "./todo-tree-grip";
import { TodoTreeDropIndicator } from "./todo-tree-drop-indicator";
import { useTodoTreeStateContext } from "../hooks/use-todo-tree-context";
import { useTodoTreeRenderContext } from "../hooks/use-todo-tree-context";
import { useTodoTreeDndContext } from "../hooks/use-todo-tree-context";
import { cn } from "@/lib/utils";

export interface TodoTreeRowProps {
  item: TodoItem;
  level: number;
  isSelected: boolean;
  isCollapsed: boolean;
  dimmed?: boolean;
  /** Permission for the drag-handle render gate. Default true. */
  canDrag?: boolean;
  /** Permission for the active-checkbox. Default true. */
  canToggleActive?: boolean;
}

/**
 * Full row: composes grip + row-content + drop-indicator + click/DnD
 * wiring. The row body is a single `<div>` that serves as
 *   - @dnd-kit droppable (id = item.id) — internal drag drop target.
 *   - HTML5 drop target (via getRowHandlers from DnD context).
 *   - HTML5 drag source (the row body itself; grip uses @dnd-kit).
 *   - click target — row-select via fire("itemClick").
 *
 * Drop indicator paints when the row is the active over-target AND the
 * computed zone isn't circular.
 */
export function TodoTreeRow({
  item,
  level,
  isSelected,
  isCollapsed,
  dimmed,
  canDrag = true,
  canToggleActive = true,
}: TodoTreeRowProps) {
  const state = useTodoTreeStateContext();
  const { indentSize, statusIndicator, renderRow } = useTodoTreeRenderContext();
  const dnd = useTodoTreeDndContext();

  const { setNodeRef, isOver } = useDroppable({ id: item.id });

  const isActiveSource = dnd?.activeItemId === item.id;
  const showIndicator =
    !!dnd &&
    isOver &&
    dnd.overId === item.id &&
    dnd.overZone !== null &&
    !dnd.overCircular;

  const rowHandlers = dnd?.getRowHandlers(item);

  const indicatorIndentPx =
    (statusIndicator === "strip" ? 12 : 8) + level * indentSize;

  const hasChildren = !!item.children && item.children.length > 0;
  const defaultRender = (
    <TodoTreeRowContent
      item={item}
      level={level}
      isSelected={isSelected}
      isCollapsed={isCollapsed}
      dimmed={dimmed}
      canToggleActive={canToggleActive}
      onToggleCollapse={() => state.toggleCollapse(item.id)}
      onToggleActive={(next) => state.toggleActive(item.id, next)}
    />
  );

  const body = renderRow
    ? renderRow({
        item,
        level,
        isSelected,
        isCollapsed,
        isExpanded: hasChildren && !isCollapsed,
        defaultRender,
      })
    : defaultRender;

  return (
    <div
      ref={setNodeRef}
      data-todo-tree-row={item.id}
      onClick={(e: MouseEvent<HTMLDivElement>) => {
        // Defensive: synthetic events from nested buttons should already
        // stopPropagation, but a slot row replacement might not.
        if (
          (e.target as HTMLElement | null)?.closest("button, input, [role='button']")
        ) {
          return;
        }
        // Move keyboard focus to the clicked row so arrow keys continue
        // from here. The treeitem div's onFocus also calls focusItem, but
        // a programmatic click from a slot may skip onFocus.
        state.focusItem(item.id);
        dnd?.handleRowClick(item, level, e);
      }}
      draggable={rowHandlers?.draggable && canDrag}
      onDragStart={rowHandlers?.onDragStart}
      onDragOver={rowHandlers?.onDragOver}
      onDrop={rowHandlers?.onDrop}
      className={cn(
        // `group` enables the grip's hover-reveal.
        "group relative flex w-full items-stretch",
        isSelected && "bg-accent/30",
        isActiveSource && "opacity-50",
        // Hover lift — applies when not dimmed by filter-fade.
        !dimmed && "hover:bg-accent/20",
      )}
    >
      {/* Grip column — leading flex item so it sits inside the row's
          bounding box (a previous absolute `-left-4` placement landed
          outside the row and was clipped by ancestor overflow:hidden /
          overflow:auto, making DnD unreachable). Always rendered
          (no `sm:` gate) because @dnd-kit's TouchSensor listeners live on
          the grip's button — hiding it on mobile would make long-press
          drag unreachable. Desktop UX still hides at rest via the
          `group-hover` class inside <TodoTreeGrip>. */}
      <span className="flex w-4 shrink-0 items-center justify-center">
        <TodoTreeGrip id={item.id} enabled={canDrag} level={level} />
      </span>

      <div className="min-w-0 flex-1">{body}</div>

      {showIndicator && dnd?.overZone && (
        <TodoTreeDropIndicator
          zone={dnd.overZone}
          indentPx={indicatorIndentPx}
        />
      )}
    </div>
  );
}

"use client";

import { useDraggable } from "@dnd-kit/core";
import { GripVertical } from "lucide-react";
import { forwardRef } from "react";
import { cn } from "@/lib/utils";

export interface TodoTreeGripProps {
  /** Stable id used as the @dnd-kit draggable id (= item.id). */
  id: string;
  /**
   * Permission gate. When false the grip renders empty (no drag affordance)
   * so the cursor doesn't suggest interaction; @dnd-kit's listeners are
   * never wired.
   */
  enabled?: boolean;
  /** Marker the @dnd-kit handlers can read off `activeId.data.current.level`. */
  level?: number;
  className?: string;
}

/**
 * Hover-revealed drag handle. The grip is invisible at rest and fades in
 * on row hover (the row sets `group` so this can use `group-hover`).
 *
 * Wires `useDraggable` from @dnd-kit/core as the activator — drag begins
 * here, NOT on the row body. That's what enables the activator mutual-
 * exclusion pattern: row-level native dragstart checks
 * `isInternalDragRef.current` and bails when the grip has already taken
 * over.
 */
export const TodoTreeGrip = forwardRef<HTMLButtonElement, TodoTreeGripProps>(
  function TodoTreeGrip({ id, enabled = true, level, className }, ref) {
    const { attributes, listeners, setNodeRef, isDragging } = useDraggable({
      id,
      data: { level },
      disabled: !enabled,
    });

    if (!enabled) return null;

    return (
      <button
        ref={(node) => {
          setNodeRef(node);
          if (typeof ref === "function") ref(node);
          else if (ref) ref.current = node;
        }}
        type="button"
        aria-label="Drag to move"
        // Stop click bubble — the grip click should not also select the row.
        onClick={(e) => e.stopPropagation()}
        {...attributes}
        {...listeners}
        className={cn(
          "inline-flex size-4 shrink-0 cursor-grab items-center justify-center rounded-sm text-muted-foreground opacity-0 transition-opacity group-hover:opacity-100 focus-visible:opacity-100 focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring",
          isDragging && "cursor-grabbing opacity-100",
          className,
        )}
      >
        <GripVertical className="size-3" />
      </button>
    );
  },
);

"use client";

import { cn } from "@/lib/utils";
import type { EdgeZone } from "../lib/edge-zone";

export interface TodoTreeDropIndicatorProps {
  /** Which slot of the over-row the indicator paints in. */
  zone: EdgeZone;
  /** Indent of the dragged-over row so the line aligns with row content. */
  indentPx?: number;
  className?: string;
}

/**
 * Visual feedback for the active drop target.
 *
 * - "top"    — 2px horizontal line at the row's top edge → sibling-before.
 * - "bottom" — 2px horizontal line at the row's bottom edge → sibling-after.
 * - "middle" — inner-glow ring around the row → reparent as last child.
 *
 * The component is absolutely positioned relative to the row's bounding box.
 * The row sets `position: relative` (already true on `TodoTreeRowContent`)
 * for this to land in the right place. Pointer events are disabled so the
 * drop event still hits the row, not this overlay.
 */
export function TodoTreeDropIndicator({
  zone,
  indentPx = 0,
  className,
}: TodoTreeDropIndicatorProps) {
  if (zone === "top" || zone === "bottom") {
    return (
      <span
        aria-hidden
        className={cn(
          "pointer-events-none absolute right-0 z-10 h-0.5 bg-primary",
          zone === "top" ? "top-0" : "bottom-0",
          className,
        )}
        style={{ left: indentPx }}
      />
    );
  }
  // zone === "middle"
  return (
    <span
      aria-hidden
      className={cn(
        "pointer-events-none absolute inset-0 z-10 rounded ring-2 ring-inset ring-primary/70",
        className,
      )}
    />
  );
}

