"use client";

import { useMemo, useState } from "react";
import { Filter, X } from "lucide-react";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { Badge } from "@/components/ui/badge";
import type {
  TodoItem,
  TodoPerson,
  TodoStatusOption,
} from "../../todo-rich-card/types";
import type { TodoTreeFilter } from "../types";
import { forEachItem } from "../lib/tree-walker";
import { cn } from "@/lib/utils";

export interface TodoTreeFilterDropdownProps {
  value: TodoTreeFilter;
  onChange: (next: TodoTreeFilter) => void;
  items: TodoItem[];
  statusOptions?: ReadonlyArray<TodoStatusOption>;
  className?: string;
}

/**
 * Multi-select Popover for status + person + clear. Status chips come from
 * the consumer's statusOptions; persons are gathered lazily from the live
 * items tree on first open (and recomputed when items change while the
 * popover is open). Empty arrays mean "no filter applied" semantically.
 */
export function TodoTreeFilterDropdown({
  value,
  onChange,
  items,
  statusOptions,
  className,
}: TodoTreeFilterDropdownProps) {
  const [open, setOpen] = useState(false);

  const persons = useMemo(() => collectPersons(items), [items]);
  const activeStatusCount = value.statuses?.length ?? 0;
  const activePersonCount = value.personIds?.length ?? 0;
  const totalActive = activeStatusCount + activePersonCount;

  const toggleStatus = (statusValue: string) => {
    const current = value.statuses ?? [];
    const next = current.includes(statusValue)
      ? current.filter((s) => s !== statusValue)
      : [...current, statusValue];
    onChange({ ...value, statuses: next });
  };

  const togglePerson = (personId: string) => {
    const current = value.personIds ?? [];
    const next = current.includes(personId)
      ? current.filter((p) => p !== personId)
      : [...current, personId];
    onChange({ ...value, personIds: next });
  };

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button
          type="button"
          variant="outline"
          size="sm"
          aria-label="Filter"
          className={cn("h-8 gap-1", className)}
        >
          <Filter className="size-3.5" />
          <span>Filter</span>
          {totalActive > 0 && (
            <Badge variant="secondary" className="ml-1 h-4 px-1 text-[10px]">
              {totalActive}
            </Badge>
          )}
        </Button>
      </PopoverTrigger>
      <PopoverContent
        className="w-72 max-h-[60vh] overflow-y-auto p-3"
        align="end"
      >
        <div className="space-y-3">
          {statusOptions && statusOptions.length > 0 && (
            <div className="space-y-1.5">
              <div className="text-xs font-medium text-muted-foreground">
                Status
              </div>
              <div className="space-y-1">
                {statusOptions.map((opt) => {
                  const checked = value.statuses?.includes(opt.value) ?? false;
                  return (
                    <label
                      key={opt.value}
                      className="flex items-center gap-2 text-sm cursor-pointer"
                    >
                      <Checkbox
                        checked={checked}
                        onCheckedChange={() => toggleStatus(opt.value)}
                      />
                      <span>{opt.label}</span>
                    </label>
                  );
                })}
              </div>
            </div>
          )}

          {persons.length > 0 && (
            <div className="space-y-1.5">
              <div className="text-xs font-medium text-muted-foreground">
                Person
              </div>
              <div className="space-y-1">
                {persons.map((p) => {
                  const checked = value.personIds?.includes(p.id) ?? false;
                  return (
                    <label
                      key={p.id}
                      className="flex items-center gap-2 text-sm cursor-pointer"
                    >
                      <Checkbox
                        checked={checked}
                        onCheckedChange={() => togglePerson(p.id)}
                      />
                      <span>{p.name}</span>
                    </label>
                  );
                })}
              </div>
            </div>
          )}

          {totalActive > 0 && (
            <Button
              type="button"
              variant="ghost"
              size="sm"
              onClick={() => onChange({ ...value, statuses: [], personIds: [] })}
              className="w-full justify-start gap-1 px-1 h-7 text-xs"
            >
              <X className="size-3" /> Clear status + person
            </Button>
          )}
        </div>
      </PopoverContent>
    </Popover>
  );
}

/**
 * Lazy person collection: walks the tree once collecting every unique
 * person id from both targetPerson and creatorPerson fields. Preserves
 * insertion order for stable rendering.
 */
function collectPersons(items: ReadonlyArray<TodoItem>): TodoPerson[] {
  const map = new Map<string, TodoPerson>();
  forEachItem(items, (item) => {
    if (item.targetPerson && !map.has(item.targetPerson.id)) {
      map.set(item.targetPerson.id, item.targetPerson);
    }
    if (item.creatorPerson && !map.has(item.creatorPerson.id)) {
      map.set(item.creatorPerson.id, item.creatorPerson);
    }
  });
  return Array.from(map.values());
}

"use client";

import { Trash2, Pencil, CheckCheck, X } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import { cn } from "@/lib/utils";

export interface TodoTreeBulkActionBarProps {
  count: number;
  /** When omitted the matching button is hidden. */
  onToggleActive?: (nextActive: boolean) => void;
  onRemove?: () => void;
  onEdit?: () => void;
  onClear?: () => void;
  className?: string;
}

/**
 * Bulk action surface — appears in the toolbar when any rows are selected.
 * Each action button is gated on the matching callback being provided;
 * `onEdit` in particular is consumer-only (bulk-edit popup isn't baked into
 * v0.1 per Q4 lock — consumers wire their own dialog).
 */
export function TodoTreeBulkActionBar({
  count,
  onToggleActive,
  onRemove,
  onEdit,
  onClear,
  className,
}: TodoTreeBulkActionBarProps) {
  if (count === 0) return null;
  return (
    <div
      role="toolbar"
      aria-label={`${count} item${count === 1 ? "" : "s"} selected`}
      className={cn(
        "inline-flex h-8 items-center gap-1 rounded-md border border-input bg-background px-1.5",
        className,
      )}
    >
      <Badge variant="secondary" className="h-5 px-1.5 text-xs">
        {count}
      </Badge>
      <Separator orientation="vertical" className="h-4" />
      {onToggleActive && (
        <>
          <Button
            type="button"
            variant="ghost"
            size="sm"
            onClick={() => onToggleActive(true)}
            className="h-6 gap-1 px-2 text-xs"
          >
            <CheckCheck className="size-3" /> Activate
          </Button>
          <Button
            type="button"
            variant="ghost"
            size="sm"
            onClick={() => onToggleActive(false)}
            className="h-6 px-2 text-xs"
          >
            Deactivate
          </Button>
        </>
      )}
      {onEdit && (
        <Button
          type="button"
          variant="ghost"
          size="sm"
          onClick={onEdit}
          className="h-6 gap-1 px-2 text-xs"
        >
          <Pencil className="size-3" /> Edit
        </Button>
      )}
      {onRemove && (
        <Button
          type="button"
          variant="ghost"
          size="sm"
          onClick={onRemove}
          className="h-6 gap-1 px-2 text-xs text-destructive hover:text-destructive"
        >
          <Trash2 className="size-3" /> Delete
        </Button>
      )}
      {onClear && (
        <Button
          type="button"
          variant="ghost"
          size="icon"
          aria-label="Clear selection"
          onClick={onClear}
          className="size-6"
        >
          <X className="size-3" />
        </Button>
      )}
    </div>
  );
}

"use client";

import { Inbox, SearchX } from "lucide-react";
import { cn } from "@/lib/utils";

export interface TodoTreeEmptyStateProps {
  /** True when the empty list is the result of a filter/search; false when the tree is genuinely empty. */
  hasFilter: boolean;
  className?: string;
}

/**
 * Default placeholder rendered when `visibleItems.length === 0`. Two
 * variants — "no matches" (filter active) vs "no tasks" (genuinely empty
 * tree). Replace via the `renderEmptyState` slot prop.
 */
export function TodoTreeEmptyState({
  hasFilter,
  className,
}: TodoTreeEmptyStateProps) {
  const Icon = hasFilter ? SearchX : Inbox;
  return (
    <div
      role="status"
      aria-live="polite"
      className={cn(
        "flex h-full flex-col items-center justify-center gap-2 px-6 py-12 text-center",
        className,
      )}
    >
      <Icon className="size-8 text-muted-foreground/60" aria-hidden />
      <div className="text-sm font-medium text-foreground">
        {hasFilter ? "No matches" : "No tasks yet"}
      </div>
      <div className="text-xs text-muted-foreground">
        {hasFilter
          ? "Adjust your search or filter to see more rows."
          : "Items added via the tree's imperative API or DnD will appear here."}
      </div>
    </div>
  );
}
